import{c as t,Q as o,j as r,m as a}from"./chunks/framework.BPKcPtvA.js";const g=JSON.parse('{"title":"How do I register a webhook?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/portal/register-webhook.md","filePath":"guide/recipes/portal/register-webhook.md","lastUpdated":1779094756000}'),i={name:"guide/recipes/portal/register-webhook.md"};function s(n,e,l,d,c,h){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="how-do-i-register-a-webhook" tabindex="-1">How do I register a webhook? <a class="header-anchor" href="#how-do-i-register-a-webhook" aria-label="Permalink to &quot;How do I register a webhook?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Owner</strong> or <strong>Admin</strong></p></div><p>Webhooks deliver events from the Console to a URL you control — useful for syncing customer data, posting to Slack, or triggering automation when something changes.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Settings → Webhooks</strong>.</li><li>Click <strong>Add Webhook</strong>.</li><li>Fill in: <ul><li><strong>Target URL</strong> — must be HTTPS and reachable from our network.</li><li><strong>Events</strong> — pick the event types you want delivered (e.g. <code>user.invited</code>, <code>tenant.created</code>, <code>invoice.issued</code>).</li><li><strong>Signing secret</strong> — generated automatically. Copy and store it in your receiving service so you can verify request signatures.</li></ul></li><li>Click <strong>Save</strong>.</li><li>Use <strong>Send Test</strong> on the webhook row to send a synthetic payload and confirm your endpoint accepts it.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>Matching events are queued and delivered to your URL with an HMAC signature in the <code>X-Signature</code> header. Failed deliveries are retried with exponential backoff for up to 24 hours.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./create-service-account">How do I create a service account / API credential?</a></li></ul>',9)])])}const p=t(i,[["render",s]]);export{g as __pageData,p as default};
